using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_67ac5b0b0590400d875450c173c42287.Auth;

/// <summary>
/// Server-side provider that simulates a logged-in user with hardcoded claims.
/// </summary>
public class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _authState = Task.FromResult(
        new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(
            new[]
            {
                new Claim(ClaimTypes.Name, "bob@example.com"),
                new Claim(ClaimTypes.Email, "bob@example.com"),
                new Claim(ClaimTypes.Role, "User"),
                new Claim(ClaimTypes.Role, "Editor"),
            },
            authenticationType: "Hardcoded"))));

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

namespace sv_67ac5b0b0590400d875450c173c42287.Auth;

/// <summary>
/// Serializable DTO that travels from server prerender to the WebAssembly client
/// via PersistentComponentState.
/// </summary>
public sealed class UserInfo
{
    public required string Name { get; set; }
    public required string[] Roles { get; set; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_67ac5b0b0590400d875450c173c42287.Auth;

/// <summary>
/// Runs on the server during prerendering. It wraps the real
/// <see cref="HardcodedAuthenticationStateProvider"/> and persists the user info
/// into <see cref="PersistentComponentState"/> so the WebAssembly client can
/// reconstruct the identity after the runtime switch.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly AuthenticationStateProvider _inner;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        AuthenticationStateProvider inner)
    {
        _persistentState = persistentState;
        _inner = inner;

        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => _inner.GetAuthenticationStateAsync();

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authStateTask = authenticationStateTask;
        NotifyAuthenticationStateChanged(authenticationStateTask);
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? GetAuthenticationStateAsync();
        var state = await authState;
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var name = principal.FindFirst(ClaimTypes.Name)?.Value;
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            if (name is not null)
            {
                _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
                {
                    Name = name,
                    Roles = roles,
                });
            }
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_67ac5b0b0590400d875450c173c42287.Client;

/// <summary>
/// Client-side (WebAssembly) provider that reads the user info persisted by the
/// server during prerendering and reconstructs the ClaimsPrincipal.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo)
            && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Name),
                new(ClaimTypes.Email, userInfo.Name),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            _authStateTask = Task.FromResult(
                new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "Persisted"))));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

/// <summary>
/// Serializable DTO matching the server-side UserInfo.
/// </summary>
public sealed class UserInfo
{
    public required string Name { get; set; }
    public required string[] Roles { get; set; }
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@attribute [Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h4>Roles</h4>
        <ul>
            @foreach (var role in context.User.FindAll(System.Security.Claims.ClaimTypes.Role))
            {
                <li>@role.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not logged in.</p>
    </NotAuthorized>
</AuthorizeView>

