using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_67ac5b0b0590400d875450c173c42287.Auth;

/// <summary>
/// Runs on the server during prerendering. It wraps the real
/// <see cref="HardcodedAuthenticationStateProvider"/> and persists the user info
/// into <see cref="PersistentComponentState"/> so the WebAssembly client can
/// reconstruct the identity after the runtime switch.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly HardcodedAuthenticationStateProvider _inner;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        HardcodedAuthenticationStateProvider inner)
    {
        _persistentState = persistentState;
        _inner = inner;

        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
